function ph_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function ph_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function ph_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;}
function ph_select2($rows,$id,$cb){$out=array();foreach($rows as $r)$out[]=array('id'=>$r->$id,'text'=>$cb($r));header('Content-Type: application/json; charset=utf-8');echo json_encode(array('results'=>$out));exit;}
function ph_filters($src){return array('from'=>isset($src['tgl_awal'])&&$src['tgl_awal']!==''?$src['tgl_awal']:date('Y-01-01'),'to'=>isset($src['tgl_akhir'])&&$src['tgl_akhir']!==''?$src['tgl_akhir']:date('Y-m-d'),'cycle_year'=>isset($src['cycle_year'])?trim($src['cycle_year']):'','appraisal_period'=>isset($src['appraisal_period'])?trim($src['appraisal_period']):'','employee_id'=>isset($src['employee_id'])?trim($src['employee_id']):'','department_code'=>isset($src['department_code'])?trim($src['department_code']):'','job_title_id'=>isset($src['job_title_id'])?trim($src['job_title_id']):'','final_rating'=>isset($src['final_rating'])?trim($src['final_rating']):'','history_status'=>isset($src['history_status'])?trim($src['history_status']):'','audit_source'=>isset($src['audit_source'])?trim($src['audit_source']):'','impact_type'=>isset($src['impact_type'])?trim($src['impact_type']):'','keyword'=>isset($src['keyword'])?trim($src['keyword']):'');}
function ph_where($f,&$p){$w=" WHERE h.appraisal_date BETWEEN ? AND ? ";array_push($p,$f['from'],$f['to']);foreach(array('cycle_year','appraisal_period','department_code','final_rating','history_status','audit_source') as $k){if($f[$k]!==''){$w.=" AND h.$k=? ";$p[]=$f[$k];}}foreach(array('employee_id','job_title_id') as $k){if($f[$k]!==''){$w.=" AND h.$k=? ";$p[]=(int)$f[$k];}}if($f['impact_type']==='HIGH')$w.=" AND h.final_rating IN ('A','B') AND h.final_score>=85 ";elseif($f['impact_type']==='LOW')$w.=" AND (h.final_rating IN ('D','E') OR h.final_score<70) ";elseif($f['impact_type']==='PIP')$w.=" AND h.improvement_required='Y' ";if($f['keyword']!==''){$kw='%'.$f['keyword'].'%';$w.=" AND (h.history_no LIKE ? OR h.appraisal_no LIKE ? OR h.employee_no LIKE ? OR h.full_name LIKE ? OR d.nm_dept LIKE ? OR jt.job_title_name LIKE ?) ";for($i=0;$i<6;$i++)$p[]=$kw;}return $w;}
$act=isset($_GET['act'])?$_GET['act']:'';
switch($act){
case 'employee_search':$t=trim(ph_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT DISTINCT employee_id id,employee_no,full_name,department_code FROM erp_performance_history WHERE (?='' OR employee_no LIKE ? OR full_name LIKE ? OR department_code LIKE ?) ORDER BY employee_no LIMIT 50",array($t,$like,$like,$like));ph_select2($rows,'id',function($r){return $r->employee_no.' - '.$r->full_name.' ['.$r->department_code.']';});
case 'department_search':$t=trim(ph_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT kd_dept,nm_dept FROM dept WHERE (?='' OR kd_dept LIKE ? OR nm_dept LIKE ?) ORDER BY kd_dept LIMIT 50",array($t,$like,$like));ph_select2($rows,'kd_dept',function($r){return $r->kd_dept.' - '.$r->nm_dept;});
case 'job_title_search':$t=trim(ph_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,job_title_code,job_title_name,job_level FROM erp_job_title WHERE (?='' OR job_title_code LIKE ? OR job_title_name LIKE ?) ORDER BY job_level DESC,job_title_code LIMIT 50",array($t,$like,$like));ph_select2($rows,'id',function($r){return $r->job_title_code.' - '.$r->job_title_name.' ['.$r->job_level.']';});
case 'detail':
  $r=$db->fetch("SELECT h.*,d.nm_dept,jt.job_title_code,jt.job_title_name,ap.employee_no appraiser_no,ap.full_name appraiser_name,hr.employee_no hr_no,hr.full_name hr_name FROM erp_performance_history h LEFT JOIN dept d ON d.kd_dept=h.department_code LEFT JOIN erp_job_title jt ON jt.id=h.job_title_id LEFT JOIN erp_employee_master ap ON ap.id=h.appraiser_employee_id LEFT JOIN erp_employee_master hr ON hr.id=h.hr_reviewer_employee_id WHERE h.id=? LIMIT 1",array((int)ph_p('id')));
  if(!$r){echo '<div class="alert alert-warning">Performance History tidak ditemukan.</div>';break;}
  $lines=$db->query("SELECT * FROM erp_performance_history_detail WHERE performance_history_id=? ORDER BY line_no,id",array((int)$r->id));
  echo '<div class="phist-detail"><h3 style="margin-top:0">'.ph_h($r->history_no).' <small>'.ph_h($r->employee_no.' - '.$r->full_name).'</small></h3><span class="label label-primary">'.ph_h($r->history_status).'</span> <span class="label label-success">Rating '.ph_h($r->final_rating).'</span><hr><div class="row"><div class="col-sm-3"><b>Appraisal</b><br>'.ph_h($r->appraisal_no?:'-').'</div><div class="col-sm-3"><b>Cycle</b><br>'.ph_h($r->cycle_year.' / '.$r->appraisal_period).'</div><div class="col-sm-3"><b>Final Score</b><br><b>'.number_format((float)$r->final_score,2).'</b></div><div class="col-sm-3"><b>Archived</b><br>'.ph_h($r->archived_at?:'-').'</div></div><hr><table class="table table-bordered table-condensed"><thead><tr><th>'.hr_h('common_no', 'No').'</th><th>KPI</th><th>Target</th><th>Weight</th><th>Actual</th><th>Self</th><th>'.hr_h('hr_manager', 'Manager').'</th><th>Weighted</th></tr></thead><tbody>';
  foreach($lines as $l){echo '<tr><td>'.(int)$l->line_no.'</td><td><b>'.ph_h($l->kpi_code).'</b><br><small>'.ph_h($l->kpi_name).'</small></td><td>'.ph_h(($l->target_text?:'-').' '.($l->unit_of_measure?:'')).'</td><td class="text-right">'.number_format((float)$l->weight,2).'%</td><td>'.ph_h($l->actual_text?:$l->actual_value?:'-').'</td><td class="text-right">'.($l->self_score!==null?number_format((float)$l->self_score,2):'-').'</td><td class="text-right">'.($l->manager_score!==null?number_format((float)$l->manager_score,2):'-').'</td><td class="text-right">'.($l->weighted_score!==null?number_format((float)$l->weighted_score,2):'-').'</td></tr>';}
  echo '</tbody></table><p><b>Development Plan:</b> '.ph_h($r->development_plan?:'-').'<br><b>Reward:</b> '.ph_h($r->reward_recommendation?:'-').'<br><b>Remarks:</b> '.ph_h($r->remarks?:'-').'</p></div>';break;
case 'export':
  $initial=ob_get_level();ob_start();error_reporting(E_ALL & ~E_NOTICE & ~E_WARNING & ~E_DEPRECATED & ~E_USER_DEPRECATED);require_once "../../inc/lib/PHPExcel.php";require_once "../../inc/excel_style_helper.php";PHPExcel_Shared_File::setUseUploadTempDirectory(true);$f=ph_filters($_GET);$p=array();$w=ph_where($f,$p);
  $rows=$db->query("SELECT h.*,d.nm_dept,jt.job_title_code,jt.job_title_name,det.line_no,det.kpi_code,det.kpi_name,det.weight,det.actual_text,det.self_score,det.manager_score,det.weighted_score FROM erp_performance_history h LEFT JOIN dept d ON d.kd_dept=h.department_code LEFT JOIN erp_job_title jt ON jt.id=h.job_title_id LEFT JOIN erp_performance_history_detail det ON det.performance_history_id=h.id $w ORDER BY h.history_no,det.line_no",$p);
  $excel=new PHPExcel();$sheet=$excel->setActiveSheetIndex(0);$sheet->setTitle(erp_export_sheet_title('Performance History'));$heads=array(erp_export_label("No"),erp_export_label("History No"),erp_export_label("Appraisal No"),erp_export_label("Employee"),erp_export_label("Department"),erp_export_label("Job Title"),erp_export_label("Year"),erp_export_label("Period"),erp_export_label("Date"),erp_export_label("KPI Score"),erp_export_label("Competency"),erp_export_label("Behavior"),erp_export_label("Final Score"),erp_export_label("Rating"),erp_export_label("History Status"),erp_export_label("Audit Source"),erp_export_label("Line"),erp_export_label("KPI Code"),erp_export_label("KPI Name"),erp_export_label("Weight"),erp_export_label("Actual"),erp_export_label("Self Score"),erp_export_label("Manager Score"),erp_export_label("Weighted"),erp_export_label("Development Plan"),erp_export_label("Updated By"));foreach($heads as $i=>$h)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).'4',$h);$rn=5;$n=1;foreach($rows as $r){$vals=array($n++,$r->history_no,$r->appraisal_no,$r->employee_no.' - '.$r->full_name,$r->department_code.' - '.$r->nm_dept,$r->job_title_code.' - '.$r->job_title_name,$r->cycle_year,$r->appraisal_period,$r->appraisal_date,$r->manager_kpi_score,$r->competency_score,$r->behavior_score,$r->final_score,$r->final_rating,$r->history_status,$r->audit_source,$r->line_no,$r->kpi_code,$r->kpi_name,$r->weight,$r->actual_text,$r->self_score,$r->manager_score,$r->weighted_score,$r->development_plan,$r->updated_by?:$r->created_by);foreach($vals as $i=>$v)$sheet->setCellValue(PHPExcel_Cell::stringFromColumnIndex($i).$rn,$v);$rn++;}
  erpkb_excel_apply_standard_style($excel,array('sheet'=>$sheet,'title'=>erp_export_title('PERFORMANCE HISTORY REPORT'),'header_row'=>4,'first_data_row'=>5,'last_data_row'=>max(5,$rn-1),'column_count'=>count($heads),'numeric_columns'=>array('J','K','L','M','Q','T','V','W','X'),'filters'=>array('Tanggal'=>$f['from'].' s/d '.$f['to'],'Year'=>$f['cycle_year']?:erp_export_all_text(),'Status'=>$f['history_status']?:erp_export_all_text()),'widths'=>array('B'=>22,'C'=>20,'D'=>28,'E'=>26,'F'=>28,'R'=>18,'S'=>30,'Y'=>34,'Z'=>18)));
  $tmp=erpkb_excel_temp_file('performance_history_');PHPExcel_IOFactory::createWriter($excel,'Excel2007')->save($tmp);$size=@filesize($tmp);$sig=@file_get_contents($tmp,false,null,0,2);if(!$size||$sig!=='PK'){@unlink($tmp);while(ob_get_level()>$initial)ob_end_clean();echo erp_t('export_excel_invalid_file','File Excel gagal dibuat dengan benar.');exit;}while(ob_get_level()>$initial)ob_end_clean();header('Content-Type: application/vnd.openxmlformats-officedocument.spreadsheetml.sheet');header('Content-Disposition: attachment; filename="performance_history_'.date('Ymd_His').'.xlsx"');header('Content-Length: '.$size);header('Cache-Control: max-age=0');header('Pragma: public');readfile($tmp);@unlink($tmp);exit;
default:ph_json('error','Action tidak dikenal.');
}
